func classify(retries int) (label string) {
	defer func() { label = fmt.Sprintf("%s:%d", label, retries) }()
	switch {
	case retries < 0:
		return "invalid"
	case retries == 0:
		return "disabled"
	default:
		return "bounded"
	}
}

